import { createDiagnosticCollector, getLocationContext, navigateProgram } from "@typespec/compiler";
import { expectDiagnostics } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { componentBlockFormRule } from "./component-block-form.rule.js";

async function runRuleDiagnostics(
  runner: Awaited<ReturnType<typeof Tester.createInstance>>,
  code: string,
) {
  await runner.compileAndDiagnose(code);
  const collector = createDiagnosticCollector();
  const ruleId = `@a10n/blueprint-typespec/${componentBlockFormRule.name}`;
  const messages = componentBlockFormRule.messages as Record<string, any>;
  const context = {
    program: runner.program,
    reportDiagnostic(diag: { messageId?: string; format?: Record<string, string>; target: any }) {
      const msgDef = messages[diag.messageId ?? "default"];
      const messageStr = typeof msgDef === "string" ? msgDef : msgDef(diag.format ?? {});
      const locCtx = getLocationContext(runner.program, diag.target);
      if (locCtx.type === "project") {
        collector.add({ code: ruleId, severity: componentBlockFormRule.severity, message: messageStr, target: diag.target } as any);
      }
    },
  };
  const listener = componentBlockFormRule.create(context as any);
  navigateProgram(runner.program, listener);
  if (listener.exit) await listener.exit(runner.program);
  return collector.diagnostics;
}

describe("component-block-form rule", () => {
  let runner: Awaited<ReturnType<typeof Tester.createInstance>>;

  beforeEach(async () => {
    runner = await Tester.createInstance();
  });

  // ── no diagnostic cases ───────────────────────────────────────────────────

  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_component_block_form
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T021.T021_01
  it("T021_01: no decorators, semicolon form — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `namespace Components.ReviewAgent;`);
    expectDiagnostics(diags, []);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T021.T021_02
  it("T021_02: @doc on block form — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @doc("desc")
      namespace Components.ReviewAgent {}
    `);
    expectDiagnostics(diags, []);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T021.T021_03
  it("T021_03: @doc on block form with newline before brace — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @doc("desc")
      namespace Components.ReviewAgent
      {
      }
    `);
    expectDiagnostics(diags, []);
  });

  // ── diagnostic cases ──────────────────────────────────────────────────────

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T021.T021_04
  it("T021_04: @doc on semicolon form — emits diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @doc("The review agent component")
      namespace Components.ReviewAgent;
    `);
    expectDiagnostics(diags, [{ code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ }]);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T021.T021_05
  it("T021_05: @component on semicolon form — linter emits diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @component(#{ type: ComponentType.Agent })
      namespace Components.ReviewAgent;
    `);
    expectDiagnostics(diags, [{ code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ }]);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T021.T021_06
  it("T021_06: @testing on semicolon form — linter emits diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @component(#{ type: ComponentType.Agent })
      namespace Components.ReviewUi {}

      @component(#{ type: ComponentType.Agent })
      @testing(Components.ReviewUi, #{ approach: TestingApproach.Real, reasoning: "real" })
      namespace Components.ReviewAgent;
    `);
    expectDiagnostics(diags, [{ code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ }]);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T021.T021_07
  it("T021_07: multiple decorators on semicolon form — one diagnostic per namespace", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @doc("a")
      @doc("b")
      namespace Components.ReviewAgent;
    `);
    // One diagnostic for the namespace (deduplicated by isSemicolonForm check)
    expectDiagnostics(diags, [{ code: "@a10n/blueprint-typespec/component-block-form" }]);
  });

  // ── augmentation cases (regression: semantic Namespace.node points to the
  // canonical block-form declaration, so decorators on a semicolon-form
  // augmentation were previously missed). The rule must walk AST nodes
  // directly to catch decorators on each declaration site. ─────────────────

  it("T021_08: block-form canonical + semicolon-form augmentation with decorator — flags the augmentation", async () => {
    // The block-form declaration (canonical) has no decorators on it.
    // The semicolon-form augmentation in another file carries @doc.
    // TypeSpec silently drops the @doc; this rule must surface it.
    const diags = await runRuleDiagnostics(runner, `
      namespace Components.ReviewAgent {}

      @doc("Augmentation that gets dropped silently")
      namespace Components.ReviewAgent;
    `);
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ },
    ]);
  });

  it("T021_09: block-form canonical with decorator + semicolon-form augmentation with decorator — flags only the augmentation", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @doc("canonical")
      namespace Components.ReviewAgent {}

      @dependsOn([Components.ReviewAgent])
      namespace Components.ReviewAgent;
    `);
    // Only the semicolon-form augmentation gets flagged — the block-form is OK.
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ },
    ]);
  });

  it("T021_10: two semicolon-form augmentations with decorators — flags both", async () => {
    const diags = await runRuleDiagnostics(runner, `
      namespace Components.ReviewAgent {}

      @doc("a")
      namespace Components.ReviewAgent;

      @doc("b")
      namespace Components.ReviewAgent;
    `);
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ },
      { code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ },
    ]);
  });

  // ── form-detection regression tests ──────────────────────────────────────
  // Earlier implementations of isSemicolonFormNode walked the source text
  // for a "{" after the "namespace" keyword. TypeSpec's parser reports
  // node.end as the position right BEFORE the opening brace for a
  // block-form namespace whose body is split across many lines, so the
  // span passed to the text walk excluded "{" entirely and the rule
  // false-flagged a block-form declaration. The current implementation
  // inspects node.statements directly. These tests pin the AST-based check.

  it("T021_11: block-form with body content + decorators — NOT flagged", async () => {
    // Mirrors products/<name>/entities/models.tsp shape: decorators on
    // namespace declaration, brace on the same line, dozens of models
    // inside. Previously triggered the text-walk false positive.
    const diags = await runRuleDiagnostics(runner, `
      @doc("Owns the desired-state layer.")
      @dependsOn([Components.ReviewAgent])
      namespace Components.ReviewAgent {
        model One {}
        model Two {}
        model Three {}
      }
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_12: block-form, brace on next line — NOT flagged", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @doc("desc")
      namespace Components.ReviewAgent
      {
        model X {}
      }
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_13: empty block-form {} with decorators — NOT flagged", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @dependsOn([Components.ReviewAgent])
      namespace Components.ReviewAgent {}
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_14: decorator value contains `{` — semicolon-form correctly detected", async () => {
    // Regression: a naive text walk over loc.pos..loc.end would find the
    // `{` inside @component(#{ ... }) and mis-classify this as block-form
    // (no warning). The form detector must start scanning AFTER the
    // namespace keyword, not from loc.pos.
    const diags = await runRuleDiagnostics(runner, `
      @component(#{ type: ComponentType.Agent })
      namespace Components.ReviewAgent;
    `);
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent/ },
    ]);
  });

  it("T021_15: decorator value contains `;` literal — block-form correctly detected", async () => {
    // The text walk past the namespace keyword must stop at the first
    // STRUCTURAL `{` or `;`, not at one inside a decorator's string arg.
    // We approximate this by putting a complex decorator that includes
    // semicolon-bearing content before the namespace; this catches a
    // simpler reverse failure mode of the same scan.
    const diags = await runRuleDiagnostics(runner, `
      @doc("a; b; c")
      namespace Components.ReviewAgent {
        model Inner {}
      }
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_16: nested intermediate dotted segment — NOT flagged", async () => {
    // For \`namespace A.B { ... }\` TypeSpec creates intermediate nodes
    // for A and A.B; only the leaf must be inspected. The walk is robust
    // either way because intermediate segments have the same `{` token.
    const diags = await runRuleDiagnostics(runner, `
      @doc("leaf has decorator")
      namespace Components.ReviewAgent.Sub {
        model X {}
      }
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_17: decorator + multi-line opening brace + body — NOT flagged", async () => {
    // Mirrors a real-world spec shape where decorators live on multiple
    // lines, the namespace keyword on its own line, body on the next.
    // Previously triggered the loc.end-too-short false positive.
    const diags = await runRuleDiagnostics(runner, `
      @doc("desc")
      @dependsOn([
        Components.ReviewAgent,
      ])
      namespace Components.ReviewAgent {
        model X {}
        model Y {}
      }
    `);
    expectDiagnostics(diags, []);
  });

  // ── dotted-namespace + complex-decorator regressions ─────────────────────
  // Real-world spec used `@storage(#{ ... })` (TypeSpec object-value
  // expression with #{...}) on dotted block-form namespace and the
  // text-walk implementation flagged it as semicolon-form. The AST-based
  // detector reads node.statements and correctly classifies it.

  it("T021_18: @storage(#{...}) decorator on empty block-form — NOT flagged", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @storage(#{
        provider: StorageProvider.git,
        root: ".",
      })
      @dependsOn([Components.ReviewAgent])
      namespace Components.MyStore { }
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_19: @component(#{type:...}) on empty block-form — NOT flagged", async () => {
    // The text-walk variant that started at loc.pos caught the `{` inside
    // #{ type: ComponentType.Agent } and (with the statements-undefined
    // fallback) mis-flagged. Direct AST detection avoids it.
    const diags = await runRuleDiagnostics(runner, `
      @component(#{ type: ComponentType.Agent })
      namespace Components.ReviewAgent { }
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_20: multi-line @storage(#{...}) on dotted block-form with body — NOT flagged", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @storage(#{
        provider: StorageProvider.git,
      })
      namespace Components.Outer.MyStore {
        model X {}
      }
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_21: dotted semicolon-form augmentation with decorator — DOES flag", async () => {
    // Confirms the detector still catches the genuine semicolon-form
    // case for a dotted FQN augmentation.
    const diags = await runRuleDiagnostics(runner, `
      namespace Components.ReviewAgent { }

      @doc("augmentation")
      namespace Components.ReviewAgent.Sub;
    `);
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/component-block-form", message: /Components\.ReviewAgent\.Sub/ },
    ]);
  });

  // ── Real-world spec scenario: same FQN declared in many sibling files,
  // one carrying decorators in block form, others as plain augmentations.
  // The block-form root MUST NOT be flagged.

  it("T021_22: block-form canonical + multiple semicolon-form augmentations without decorators — NOT flagged", async () => {
    const diags = await runRuleDiagnostics(runner, `
      @doc("canonical")
      @dependsOn([Components.ReviewAgent])
      namespace Components.MyService { }

      namespace Components.MyService;

      namespace Components.MyService;
    `);
    expectDiagnostics(diags, []);
  });

  it("T021_23: empty block-form root with @component + @dependsOn + @testing — NOT flagged", async () => {
    // Direct mirror of components/a10n-state-file-store/main.tsp shape
    // that previously misfired.
    const diags = await runRuleDiagnostics(runner, `
      @storage(#{
        provider: StorageProvider.git,
        root: ".",
      })
      @component(#{ type: ComponentType.Store })
      @dependsOn([Components.ReviewAgent])
      namespace Components.MyStore { }
    `);
    expectDiagnostics(diags, []);
  });
});
